powershell -Command @"
node -e "
const fs = require('fs');
const path = require('path');

const MEMORY_DIR = 'G:\\AI\\AIMemory';
const USER_ID = '509424983';
const factsFile = path.join(MEMORY_DIR, 'facts-' + USER_ID + '.md');
const topicsFile = path.join(MEMORY_DIR, 'topics.json');
const shardDir = path.join(MEMORY_DIR, 'facts_Topic', USER_ID);

// Read topics (strip JS comments)
const topicsRaw = fs.readFileSync(topicsFile, 'utf8');
const topicsClean = topicsRaw.replace(/\/\/.*$/gm, '');
const topics = JSON.parse(topicsClean);

// Read facts
const factsRaw = fs.readFileSync(factsFile, 'utf8');
const lines = factsRaw.split(/\r?\n/).filter(l => l.trim().startsWith('- ['));

// Classify
const shards = {};
topics.forEach(t => { shards[t.topic] = []; });
shards['misc'] = [];

for (const line of lines) {
  const lower = line.toLowerCase();
  let matched = false;
  for (const rule of topics) {
    for (const kw of rule.keywords) {
      if (lower.includes(kw)) {
        shards[rule.topic].push(line);
        matched = true;
        break;
      }
    }
    if (matched) break;
  }
  if (!matched) shards['misc'].push(line);
}

// Report
console.log('=== Topic Review Results ===');
let total = 0;
for (const [topic, facts] of Object.entries(shards)) {
  if (facts.length > 0) {
    console.log(topic + ': ' + facts.length);
    total += facts.length;
  }
}
console.log('---');
console.log('Total classified: ' + total + ' / ' + lines.length);
console.log('');
if (shards['misc'].length > 0) {
  console.log('=== MISC facts ===');
  shards['misc'].forEach(f => console.log(f.substring(0, 120)));
}

// Write shards
if (!fs.existsSync(shardDir)) fs.mkdirSync(shardDir, { recursive: true });
// Clear old shards
for (const f of fs.readdirSync(shardDir)) {
  fs.unlinkSync(path.join(shardDir, f));
}
// Write new shards
for (const [topic, facts] of Object.entries(shards)) {
  if (facts.length > 0) {
    fs.writeFileSync(path.join(shardDir, topic + '.md'), facts.join('\n') + '\n', 'utf8');
  }
}
console.log('');
console.log('Shards rebuilt successfully.');
"
"@

