/**
 * factlint-delete.js — CRLF-safe fact deletion
 * Mimics MCP forget() safety: CRLF-aware split + empty-write guard + ratio guard + pre-write backup
 */
const fs = require('fs');
const path = require('path');

const MEMORY_DIR = 'G:\\AI\\AIMemory';
const USER_ID = '509424983';
const factsFile = path.join(MEMORY_DIR, `facts-${USER_ID}.md`);
const shardDir = path.join(MEMORY_DIR, 'facts_Topic', USER_ID);

// Facts to delete (distinctive substring for each)
const DELETE_IDS = [
  'f_1ff1d5',
  'f_510f59',
  'f_dd04ac',
  'f_a10e66',
  'f_07d587',
  'f_d274c6',
  'f_bdc742',
  'f_1a894e',
];

// Read with CRLF-safe split
const raw = fs.readFileSync(factsFile, 'utf8');
const lines = raw.split(/\r?\n/);

// Filter out lines containing any DELETE_ID
const kept = lines.filter(line => {
  for (const id of DELETE_IDS) {
    if (line.includes(`[${id}]`)) return false;
  }
  return true;
});

const originalFactLines = lines.filter(l => l.trim().startsWith('- ['));
const keptFactLines = kept.filter(l => l.trim().startsWith('- ['));
const deletedCount = originalFactLines.length - keptFactLines.length;

console.log(`Original fact lines: ${originalFactLines.length}`);
console.log(`Kept fact lines: ${keptFactLines.length}`);
console.log(`To delete: ${deletedCount}`);

// Safety guard 1: empty-write protection
if (keptFactLines.length === 0) {
  console.error('⛔ ABORT: kept=0, would destroy all facts!');
  process.exit(1);
}

// Safety guard 2: ratio guard (>50% deletion)
const ratio = deletedCount / originalFactLines.length;
console.log(`Deletion ratio: ${(ratio * 100).toFixed(1)}%`);
if (ratio > 0.5) {
  console.error(`⛔ ABORT: deletion ratio ${(ratio * 100).toFixed(1)}% > 50%!`);
  process.exit(1);
}

// Safety guard 3: pre-write backup
const timestamp = Date.now();
const backupPath = factsFile + `.bak.${timestamp}`;
fs.copyFileSync(factsFile, backupPath);
console.log(`Backup: ${backupPath}`);

// Write (preserve original line ending style)
const useCRLF = raw.includes('\r\n');
const newContent = kept.join(useCRLF ? '\r\n' : '\n');
fs.writeFileSync(factsFile, newContent, 'utf8');
console.log(`✅ Written. ${deletedCount} facts removed.`);

// Rebuild shards
const topicsRaw = fs.readFileSync(path.join(MEMORY_DIR, 'topics.json'), 'utf8');
const topicsClean = topicsRaw.replace(/\/\/.*$/gm, '');
const topics = JSON.parse(topicsClean);

const factLines = newContent.split(/\r?\n/).filter(l => l.trim().startsWith('- ['));
const shards = {};
topics.forEach(t => { shards[t.topic] = []; });
shards['misc'] = [];

for (const line of factLines) {
  const lower = line.toLowerCase();
  let matched = false;
  for (const rule of topics) {
    for (const kw of rule.keywords) {
      if (lower.includes(kw)) {
        shards[rule.topic].push(line);
        matched = true;
        break;
      }
    }
    if (matched) break;
  }
  if (!matched) shards['misc'].push(line);
}

// Clear and rewrite shards
for (const f of fs.readdirSync(shardDir)) {
  fs.unlinkSync(path.join(shardDir, f));
}
for (const [topic, facts] of Object.entries(shards)) {
  if (facts.length > 0) {
    const shardContent = facts.join(useCRLF ? '\r\n' : '\n') + (useCRLF ? '\r\n' : '\n');
    fs.writeFileSync(path.join(shardDir, topic + '.md'), shardContent, 'utf8');
  }
}

console.log('\nShard rebuild:');
for (const [topic, facts] of Object.entries(shards)) {
  if (facts.length > 0) console.log(`  ${topic}: ${facts.length}`);
}
console.log(`\nTotal remaining: ${factLines.length}`);

